const input=$json.body??$json;
for(const field of ['client_id','source_event_id','workflow_name','source_system','records','field_map']) if(input[field]===undefined||input[field]===null) throw new Error(`Missing required field: ${field}`);
if(!['crm','spreadsheet','portal'].includes(input.source_system)) throw new Error('source_system must be crm, spreadsheet, or portal');
if(!Array.isArray(input.records)||input.records.length===0) throw new Error('records must be a non-empty array');
const seen=new Set(); const failed=[]; const records=[]; const entityRefs=[];
for(const record of input.records){ const externalId=String(record.external_id??''); const key=`${input.source_system}:${externalId}`; if(!externalId||!record.entity_type||seen.has(key)){ failed.push(externalId||'missing-external-id'); continue; } seen.add(key); records.push({record_key:key,external_id:externalId,entity_type:record.entity_type,fields:record.fields??{},mapped_fields:Object.fromEntries(Object.entries(input.field_map).map(([from,to])=>[to,record.fields?.[from]??null]))}); if(['lead','listing','appointment'].includes(record.entity_type)&&record.entity_id) entityRefs.push({entity_type:record.entity_type,entity_id:record.entity_id,action:'synced',source_system:input.source_system,external_id:externalId}); }
return [{json:{...input,event_id:`${input.client_id}:data_sync:${input.source_event_id}`,feature_type:'system_data_synchronization',records,failed_record_ids:failed,records_processed:0,records_failed:failed.length,entity_refs:entityRefs,workflow_steps:[{step_key:'validate_batch',step_name:'Validate and deduplicate batch',status:'success'}]}}];
